import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';

const API_BASE = 'http://localhost:8000';
const WS_URL = 'ws://localhost:8000/ws/stream';

const STATUS_COLOR = {
    open: '#ff5252',
    investigated: '#29b6f6',
    closed_false_positive: '#4caf50',
    escalated: '#ff9800',
};

export default function AutonomousSocAnalystPanel() {
    const [summary, setSummary] = useState({ total_alerts: 0, investigated: 0, false_positive_closed: 0, classifications: [] });
    const [findings, setFindings] = useState([]);
    const [running, setRunning] = useState(false);
    const [wsState, setWsState] = useState('disconnected');
    const timerRef = useRef(null);

    const refresh = useCallback(() => {
        Promise.all([
            fetch(`${API_BASE}/api/ai-analyst/summary`).then((r) => r.json()),
            fetch(`${API_BASE}/api/ai-analyst/findings?limit=20`).then((r) => r.json()),
        ])
            .then(([s, f]) => {
                setSummary(s || {});
                setFindings(Array.isArray(f) ? f : []);
            })
            .catch(() => {
                // keep current values for resilience
            });
    }, []);

    const runAutonomous = useCallback(() => {
        setRunning(true);
        fetch(`${API_BASE}/api/ai-analyst/run?limit=200`, { method: 'POST' })
            .then(() => refresh())
            .finally(() => setRunning(false));
    }, [refresh]);

    const setDisposition = useCallback((id, disposition) => {
        fetch(`${API_BASE}/api/ai-analyst/alerts/${id}/disposition?disposition=${encodeURIComponent(disposition)}`, {
            method: 'PATCH',
        }).then(() => refresh());
    }, [refresh]);

    useEffect(() => {
        refresh();
        timerRef.current = setInterval(refresh, 14000);
        return () => clearInterval(timerRef.current);
    }, [refresh]);

    useEffect(() => {
        let ws;
        try {
            ws = new WebSocket(WS_URL);
            ws.onopen = () => {
                setWsState('connected');
                ws.send('ping');
            };
            ws.onclose = () => setWsState('disconnected');
            ws.onerror = () => setWsState('error');
            ws.onmessage = (msg) => {
                try {
                    const parsed = JSON.parse(msg.data);
                    if (['analyst_update', 'new_alert'].includes(parsed.event)) {
                        refresh();
                    }
                } catch {
                    // ignore malformed events
                }
            };
        } catch {
            setWsState('error');
        }
        return () => {
            if (ws && ws.readyState <= 1) ws.close();
        };
    }, [refresh]);

    const wsBadge = useMemo(() => {
        if (wsState === 'connected') return { label: 'AI STREAM LIVE', color: '#4caf50' };
        if (wsState === 'error') return { label: 'AI STREAM ERROR', color: '#ff5252' };
        return { label: 'AI STREAM OFFLINE', color: '#607d8b' };
    }, [wsState]);

    return (
        <section
            style={{
                background: '#060c14',
                border: '1px solid #1a3a4a',
                borderRadius: 10,
                padding: 14,
                margin: '12px 0',
                color: '#d0e8ff',
                fontFamily: 'JetBrains Mono, monospace',
            }}
        >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span style={{ color: '#29b6f6', fontWeight: 700, letterSpacing: '0.08em', fontSize: '0.84rem' }}>
                        AUTONOMOUS AI SOC ANALYST
                    </span>
                    <span style={{ fontSize: '0.66rem', border: `1px solid ${wsBadge.color}66`, color: wsBadge.color, borderRadius: 999, padding: '2px 8px' }}>
                        {wsBadge.label}
                    </span>
                </div>
                <div style={{ display: 'flex', gap: 8 }}>
                    <button
                        onClick={refresh}
                        style={{
                            background: 'transparent',
                            border: '1px solid #29b6f6',
                            borderRadius: 4,
                            color: '#29b6f6',
                            cursor: 'pointer',
                            fontSize: '0.72rem',
                            padding: '3px 10px',
                        }}
                    >
                        ↺ Refresh
                    </button>
                    <button
                        onClick={runAutonomous}
                        disabled={running}
                        style={{
                            background: running ? '#607d8b' : '#ab47bc',
                            border: 'none',
                            borderRadius: 4,
                            color: '#fff',
                            cursor: 'pointer',
                            fontSize: '0.72rem',
                            fontWeight: 700,
                            padding: '3px 10px',
                        }}
                    >
                        {running ? 'Running…' : 'Run Autonomous Investigation'}
                    </button>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(120px, 1fr))', gap: 8, marginBottom: 10 }}>
                <div style={{ border: '1px solid #1a3a4a', borderRadius: 6, padding: 8 }}>
                    <div style={{ color: '#78909c', fontSize: '0.68rem' }}>Total Alerts</div>
                    <div style={{ fontSize: '1rem', fontWeight: 700 }}>{summary.total_alerts || 0}</div>
                </div>
                <div style={{ border: '1px solid #1a3a4a', borderRadius: 6, padding: 8 }}>
                    <div style={{ color: '#78909c', fontSize: '0.68rem' }}>Investigated</div>
                    <div style={{ fontSize: '1rem', fontWeight: 700, color: '#29b6f6' }}>{summary.investigated || 0}</div>
                </div>
                <div style={{ border: '1px solid #1a3a4a', borderRadius: 6, padding: 8 }}>
                    <div style={{ color: '#78909c', fontSize: '0.68rem' }}>False Positives Closed</div>
                    <div style={{ fontSize: '1rem', fontWeight: 700, color: '#4caf50' }}>{summary.false_positive_closed || 0}</div>
                </div>
                <div style={{ border: '1px solid #1a3a4a', borderRadius: 6, padding: 8 }}>
                    <div style={{ color: '#78909c', fontSize: '0.68rem' }}>Top Class</div>
                    <div style={{ fontSize: '0.8rem', fontWeight: 700, color: '#ff9800' }}>{summary.classifications?.[0]?.classification || '—'}</div>
                </div>
            </div>

            <div style={{ border: '1px solid #1a3a4a', borderRadius: 8, padding: 8 }}>
                <div style={{ color: '#78909c', fontSize: '0.72rem', marginBottom: 6 }}>Latest Autonomous Findings</div>
                <div style={{ maxHeight: 260, overflowY: 'auto' }}>
                    {findings.length === 0 && <div style={{ color: '#546e7a', fontSize: '0.72rem' }}>No findings yet.</div>}
                    {findings.map((f) => {
                        const s = f.analyst_status || 'open';
                        return (
                            <div key={f.id} style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid #1a3a4a', borderRadius: 6, padding: 8, marginBottom: 7 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                                    <div>
                                        <div style={{ fontSize: '0.75rem', color: '#e8f4ff' }}>{f.alert_type} · {f.matched_indicator}</div>
                                        <div style={{ fontSize: '0.68rem', color: '#8ab4c7', marginTop: 2 }}>
                                            class: {f.attack_classification || 'pending'} · confidence: {f.analyst_confidence != null ? Number(f.analyst_confidence).toFixed(2) : '—'}
                                        </div>
                                    </div>
                                    <span style={{ fontSize: '0.65rem', color: STATUS_COLOR[s] || '#9e9e9e', border: `1px solid ${(STATUS_COLOR[s] || '#9e9e9e')}66`, borderRadius: 4, padding: '2px 6px', height: 'fit-content' }}>
                                        {s}
                                    </span>
                                </div>

                                {f.analyst_recommendation && (
                                    <div style={{ marginTop: 6, fontSize: '0.7rem', color: '#cfe8ff' }}>
                                        {f.analyst_recommendation}
                                    </div>
                                )}

                                <div style={{ marginTop: 6, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                                    <button onClick={() => setDisposition(f.id, 'investigated')} style={{ fontSize: '0.64rem', padding: '2px 7px', borderRadius: 4, border: '1px solid #29b6f666', color: '#29b6f6', background: 'transparent', cursor: 'pointer' }}>Investigated</button>
                                    <button onClick={() => setDisposition(f.id, 'closed_false_positive')} style={{ fontSize: '0.64rem', padding: '2px 7px', borderRadius: 4, border: '1px solid #4caf5066', color: '#4caf50', background: 'transparent', cursor: 'pointer' }}>Close FP</button>
                                    <button onClick={() => setDisposition(f.id, 'escalated')} style={{ fontSize: '0.64rem', padding: '2px 7px', borderRadius: 4, border: '1px solid #ff980066', color: '#ff9800', background: 'transparent', cursor: 'pointer' }}>Escalate</button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </section>
    );
}
